            if (buffer.assignParameter(creatorProp, creatorProp.deserialize(p, ctxt))) {
                t = p.nextToken();
                Object bean;
                try {
                    bean = creator.build(ctxt, buffer);
                } catch (Exception e) {
                    wrapAndThrow(e, _beanType.getRawClass(), propName, ctxt);
                    continue;
                }
                // Buffer any remaining fields for the bean
                while (t == JsonToken.FIELD_NAME) {
                    p.nextToken();
                    tokens.copyCurrentStructure(p);
                    t = p.nextToken();
                }
                tokens.writeEndObject();
                // Ensure the bean is of the correct type
                if (bean.getClass() != _beanType.getRawClass()) {
                    ctxt.reportMappingException("Cannot create polymorphic instances with unwrapped values");
                    return null;
                }
                return _unwrappedPropertyHandler.processUnwrapped(p, ctxt, bean, tokens);
            }
            continue;
        }
        // Handle Object Id property
        if (buffer.readIdProperty(propName)) {
            continue;
        }
        // Handle regular properties
        SettableBeanProperty prop = _beanProperties.find(propName);
        if (prop != null) {
            buffer.bufferProperty(prop, prop.deserialize(p, ctxt));
            continue;
        }
        // Handle ignored properties
        if (_ignorableProps != null && _ignorableProps.contains(propName)) {
            handleIgnoredProperty(p, ctxt, handledType(), propName);
            continue;
